head.script:
scwin.sDate = $c.date.formatDateTime(new Date());
scwin.vCurDate = $c.date.getServerDateTime();
scwin.vQryStDt = $c.date.getDateAddMonthDirection(scwin.vCurDate, 0 , "F");  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
scwin.vQryEndDt = $c.date.getDateAddMonthDirection(scwin.vCurDate, 0 , "L");  // 조회종료일자(현재 날짜가 포함된 달의 마지막 일자) 

scwin.isFilter = true;

scwin.onpageload = function () {
    ds_condition.insertRow(0);
    ds_condition.setRowPosition(0);

    const codeOptions = [
         { grpCd : "SD070", compID : "acb_taxnClsCd", opt:{"range":"1"} } // 과세구분
       , { grpCd : "FS500", compID : "gr_out:dcsnClsCd", opt:{"range":"1"} }   
    ];
    $c.data.setCommonCode(codeOptions);
};

scwin.onUdcCompleted = function () {
    udc_qryConDt.setInitDate(scwin.vQryStDt, scwin.vQryEndDt);
    acb_qryDtConKnd.setValue("CERTI"); 
    acb_taxnClsCd.setValue("01");  
    ed_homeClntNo.focus();

    // 테스트데이터
    // ed_homeClntNo.setValue("317302");
    // ed_homeClntNm.setValue("㈜지에스리테일 파주 물류센터");
    // udc_qryConDt.setInitDate("20240301", "20260331");

    $c.gus.cfDisableBtnOnly([btn_save]);

    $c.gus.cfEnableObj(ica_slipCloseYm, false);
    $c.gus.cfEnableObj(ica_taxCloseYm, false);    
};

scwin.ondataload = function () {

};

//-------------------------------------------------------------------------
// Function
//-------------------------------------------------------------------------
// 조회
scwin.f_Retrieve = async function () {
    // validation check
    if (!await $c.gus.cfValidate([ed_homeClntNo])) {
        return;
    }

    // 조회시작일자가 더 클경우 체크
    if (!await $c.gus.cfIsAfterDate(ed_qryConDtFm.getValue(), ed_qryConDtTo.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        return;
    }

    if (acb_qryDtConKnd.getValue() == "CERTI") {
        let e = await $c.sbm.execute(sbm_retrieve);
        if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
            scwin.sbm_retrieve_submitdone(e);
        }
    } else if (acb_qryDtConKnd.getValue() == "SPPLY" || acb_qryDtConKnd.getValue() == "POST") {
        let e = await $c.sbm.execute(sbm_eachSellingEvidenceList);
        if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
            scwin.sbm_eachSellingEvidenceList_submitdone(e);
        }
    }
};

// 하단그리드 조회
scwin.f_DetailRetrieve = async function(row) {
    ds_condition_con.insertRow(0);
    ds_condition_con.setRowPosition(0)

    ds_condition_con.setCellData(0, "slipNo", ds_out.getCellData(row, "slipNo"));

    let e = await $c.sbm.execute(sbm_detail_retrieve);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        scwin.sbm_detail_retrieve_submitdone(e);
    }
};

// 조회조건 Clear
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tbl_search, null);

    ed_qryConDtFm.setValue(scwin.vQryStDt);
    ed_qryConDtTo.setValue(scwin.vQryEndDt);
    acb_qryDtConKnd.setValue("CERTI"); 
    acb_taxnClsCd.setValue("01");       

    ed_homeClntNo.focus();
};

// 저장
scwin.f_Save = async function () {
    if (ds_out.getRowCount() < 1 || ds_detail.getRowCount() < 1) {
        return;
    }  	

    $c.gus.cfCopyDataSetHeader(ds_out, ds_saveOut);
    var	transRow;
    var chkCnt = 0; 

    for (var i = 0; i < ds_out.getRowCount(); i++) {
        if (ds_out.getCellData(i, "choice") == "T") { 
            if (ds_out.getCellData(i, "spplyDt") == null || ds_out.getCellData(i, "spplyDt") == "") {
                await $c.gus.cfAlertMsg("청구세금계산서 내역의 " + (i + 1) + "번째 데이터에 공급일자는 필수입력 항목입니다.");
                return;
            }
            if (ds_out.getCellData(i, "slipDt") == null || ds_out.getCellData(i, "slipDt") == "") {
                await $c.gus.cfAlertMsg("청구세금계산서 내역의 " + (i + 1) +"번째 데이터에 전표일자는 필수입력 항목입니다.");
                return;
            }
            if (ds_out.getCellData(i, "goods") == null || ds_out.getCellData(i, "goods") == "") {
                await $c.gus.cfAlertMsg("청구세금계산서 내역의 " + (i + 1) +"번째 데이터에 품명은 필수입력 항목입니다.");
                return;
            }

            // 세금계산서거 발행되었으면....
            if (ds_out.getCellData(i, "slipNo") != null && ds_out.getCellData(i, "slipNo") != "") {
                await $c.gus.cfAlertMsg("청구세금계산서 내역의 " + (i + 1) + "번째 데이터는 매출증빙 내역이 있는 자료입니다.\n일괄저장 할 수 없습니다.");
                return;
            }

            transRow = ds_out.getRowJSON(i);
            var rowIndex = ds_saveOut.insertRow();
            ds_saveOut.setRowJSON(rowIndex, transRow, true); 
            ds_saveOut.setCellData(rowIndex, "curRow", i);
            chkCnt++;
        }
    }

    scwin.isFilter = false;
    $c.gus.cfCopyDataSetHeader(ds_detail, ds_saveDetail); 

    var	transRow2;
    var chkCnt2 = 0;

    for (var i = 0; i < ds_detail.getRowCount(); i++) {
        if (ds_detail.getCellData(i, "choice") == "T") {
            if (ds_out.getCellData(ds_out.getMatchedIndex('bilgClntNo', ds_detail.getCellData(i, "bilgClntNo")), "choice") == "T") {
                transRow2 = ds_detail.getRowJSON(i);
                var rowIndex = ds_saveDetail.insertRow();
                ds_saveDetail.setRowJSON(rowIndex, transRow2, true); 
                chkCnt2++;
            }
        }
    }

    scwin.isFilter = true;

    if (chkCnt < 1 || chkCnt2 < 1) { 
        $c.gus.cfAlertMsg(MSG_CM_WRN_007,["저장할 자료"]);
        return;
    }

    let saveChk = await $c.win.confirm(MSG_CM_CRM_001); 
    if (!saveChk) { 
        return;
    } 

    let e = await $c.sbm.execute(sbm_save);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        scwin.sbm_save_submitdone(e);
    }
};

// 팝업창 처리
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    var rtnList  = new Array();  // 공통POP-UP -> 요청화면
    switch (disGubun) {
        case 1:
            // 소속거래처    
            udc_homeClntNo.setSelectId("retrieveSubsidaryClntListJa"); 
            rtnList = await udc_homeClntNo.cfCommonPopUpAsync(
                                                                      ''  	                            // XML상의 SELECT ID
                                                                    , pCode								// 화면에서의 ??? Code Element의	Value
                                                                    , pName								// 화면에서의 ??? Name Element의	Value
                                                                    , pClose							// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                                                    , '5'								// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                                                    , null								// Title순서
                                                                    , '150,170'  		    			// 보여주는 각 컬럼들의 폭
                                                                    , null								// 컬럼중에서 숨기는	컬럼 지정
                                                                    , null								// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                                                    , null								// POP-UP뛰을때 원도우의	사용자 정의	폭
                                                                    , null								// POP-UP뛰을때 우도우의	사용자 정의	높이
                                                                    , null								// 윈도우 위치 Y좌표
                                                                    , null								// 윈도우 위치 X좌표
                                                                    , null								// 중복체크여부	("F")
                                                                    , pAllSearch						// 전체검색허용여부	("F")
                                                                    , "소속거래처,거래처코드,거래처명"	  // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                                            );
			if (rtnList != null) {
				$c.gus.cfSetReturnValue(rtnList, ed_homeClntNo, ed_homeClntNm);
			}
        break;
        case 2:
            // 차량번호
            udc_vehclNo.setSelectId("retrieveSubsidaryVehclList"); 
            rtnList = await udc_vehclNo.cfCommonPopUpAsync(
                                                                  ''   	                            // XML상의 SELECT ID
                                                                , pCode                             // 화면에서의 ??? Code Element의  Value
                                                                , pName                             // 화면에서의 ??? Name Element의  Value
                                                                , pClose                            // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                                                                , null                              // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                                                                , null                              // Title순서  
                                                                , null                              // 보여주는 각 컬럼들의 폭    
                                                                , null                              // 컬럼중에서 숨기는    컬럼 지정   
                                                                , null                              // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                                                                , "400"                             // POP-UP뛰을때 원도우의   사용자 정의  폭
                                                                , null                              // POP-UP뛰을때 우도우의   사용자 정의  높이  
                                                                , null                              // 윈도우 위치 Y좌표   
                                                                , null                              // 윈도우 위치 X좌표
                                                                , null                              // 중복체크여부   ("F")
                                                                , pAllSearch                        // 전체검색허용여부 ("F")
                                                                , "차량번호,차량단축코드,차량번호"    // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                    );
            if (rtnList != null) {
                $c.gus.cfSetReturnValue(rtnList, ed_vehclNoCd, ed_vehclNo);
            }	
        break;
        default:
        break;
    }
};

// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    } else {
        // inObj가 코드명 필드일 경우 팝업
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

// 세금계산서 출력
scwin.f_Print = async function () {
    var param = "";
    var printCnt = 0;

    for (var i = 0; i < ds_out.getRowCount(); i++) {

        if (ds_out.getCellData(i, "printChk") == "T") {
            param = param + ",TO_CHAR(" + ds_out.getCellData(i, "sellVatNo") + ")";  // 계산서번호
            printCnt++; 
        }
    }

    if (printCnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["발행할 세금계산서"]);  // @을(를) 선택하십시오.
        return;
    }

    const data = {
        reportName: "/ac/fi/taxbiz/vatctrl/fi_401_01_09p_2.ozr",
        odiName : "fi_401_01_09p",
        odiParam: {
            pchsSellCls : param.substring(1),
        },
        viewerParam: {
            mode : "preview",
        },
        formParam: {}
    };

    await scwin.openPopup(data);
};

scwin.openPopup = async function(data) {
    let opts = {
        id: "ozReportPopup",
        popupName: "오즈 리포트",
        modal: true,
        type: "browserPopup",
        width: 1000,
        height: 600,
        title: "오즈 리포트"
    };
    await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
};

// 청구처 그리드데이터 선택에 따른 디테일 그리드 데이터 필터링
scwin.f_onFilter = function (row) {
    if (scwin.isFilter) {
        let condition = "bilgClntNo == '" + ds_out.getCellData($c.gus.cfIsNull(ds_out.getRowPosition()) ? 0 : ds_out.getRowPosition(), "bilgClntNo") + "'";
        ds_detail.removeColumnFilterAll();
        $c.data.dataListFilter(ds_detail, condition);
        totalRowsDetail.setValue(ds_detail.getRowCount());
	} else {
		return true;
	}
};

//-------------------------------------------------------------------------
// Sbm submitdone
//-------------------------------------------------------------------------
scwin.sbm_retrieve_submitdone = async function (e) {
	totalRowsOut.setValue(ds_out.getRowCount());
    totalRowsDetail.setValue(ds_detail.getRowCount());

    ica_slipCloseYm.setValue(ds_out.getCellData(0, "slipCloseYm"));	  // 회계마감월
	ica_taxCloseYm.setValue(ds_out.getCellData(0, "taxCloseYm"));	  // 세무마감월

	if (ds_out.getRowCount() > 0) {
		if (ds_out.getCellData(0, "slipNo") != null && ds_out.getCellData(0, "slipNo") != "") {
			scwin.f_DetailRetrieve("0");

			//////ds_detail.UseFilter = false;
            $c.gus.cfDisableBtnOnly([btn_save]);
		} else {	
			//////ds_detail.UseFilter = true;
			$c.gus.cfEnableBtnOnly([btn_save]);
		}
        scwin.f_onFilter(0);
        gr_out.setColumnReadOnly('choice', false);
        gr_out.setColumnReadOnly('printChk', true);
	} else {
        $c.gus.cfDisableBtnOnly([btn_save]);
		if (await $c.gus.cfAlertMsg(MSG_CM_WRN_002)) {
            ds_detail.removeAll();	
        };
	}
};

scwin.sbm_eachSellingEvidenceList_submitdone = async function (e) {
	totalRowsOut.setValue(ds_out.getRowCount());
    totalRowsDetail.setValue(ds_detail.getRowCount());

    ica_slipCloseYm.setValue(ds_out.getCellData(0, "slipCloseYm"));	  // 회계마감월
	ica_taxCloseYm.setValue(ds_out.getCellData(0, "taxCloseYm"));	  // 세무마감월

	if (ds_out.getRowCount() > 0) {
		if (ds_out.getCellData(0, "slipNo") != null && ds_out.getCellData(0, "slipNo") != "") {
			scwin.f_DetailRetrieve("0");

			//////ds_detail.UseFilter = false;
            $c.gus.cfDisableBtnOnly([btn_save]);
		} else {	
			//////ds_detail.UseFilter = true;
			$c.gus.cfEnableBtnOnly([btn_save]);
		}
        scwin.f_onFilter(0);

        gr_out.setColumnReadOnly('choice', true);
        gr_out.setColumnReadOnly('printChk', false);
	} else {
        $c.gus.cfDisableBtnOnly([btn_save]);
		if (await $c.gus.cfAlertMsg(MSG_CM_WRN_002)) {
            ds_detail.removeAll();	
        };
	}
};

scwin.sbm_detail_retrieve_submitdone = async function (e) {
    totalRowsDetail.setValue(ds_detail.getRowCount());
};

scwin.sbm_save_submitdone = async function (e) {
    if (await $c.gus.cfAlertMsg(MSG_CM_INF_001)) {
        scwin.f_Retrieve(); 
    }
};

//-------------------------------------------------------------------------
// Event onClick
//-------------------------------------------------------------------------
// 조회 버튼 클릭 이벤트 
scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};

// 초기화 버튼 클릭 이벤트 
scwin.btn_fieldClear_onclick = function (e) {
    scwin.f_FieldClear();
};

// 일광생성 버튼 클릭 이벤트 
scwin.btn_save_onclick = function (e) {
    scwin.f_Save();
};

// 세금계산서 출력 버튼 클릭 이벤트 
scwin.btn_print_onclick = function (e) {
    scwin.f_Print();
};

// 소속거래처 찾기 출력 버튼 클릭 이벤트 
scwin.udc_homeClntNo_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_homeClntNo.getValue(), ed_homeClntNm.getValue(), 'F', 'F');
};

// 차량번호 찾기 출력 버튼 클릭 이벤트 
scwin.udc_vehclNo_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(2, ed_vehclNoCd.getValue(), ed_vehclNo.getValue(), 'F', 'T');
};

//-------------------------------------------------------------------------
// Event onblur
//-------------------------------------------------------------------------
// 소속거래처 Onbluer(onKillFocus) 이벤트 발생시
scwin.udc_homeClntNo_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_homeClntNo, ed_homeClntNm, 1);
};

// 차량번호호 Onbluer(onKillFocus) 이벤트 발생시
scwin.udc_vehclNo_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_vehclNoCd, ed_vehclNo, 2);
};

//-------------------------------------------------------------------------
// Event onviewchange
//-------------------------------------------------------------------------
// 소속거래처 onviewchange 이벤트 발생시
scwin.udc_homeClntNo_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_homeClntNm, ed_homeClntNo, 1, false);
};

// 차량번호 onviewchange 이벤트 발생시
scwin.udc_vehclNo_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_vehclNo, ed_vehclNoCd, 2, false);
};

//-------------------------------------------------------------------------
// DataSet 이벤트
//-------------------------------------------------------------------------
scwin.ds_outSellingEvidenceList_ondataload = function () {debugger;
	for (var i = 0; i < ds_outSellingEvidenceList.getRowCount(); i++) {
        var targetIndex = ds_outSellingEvidenceList.getCellData(i, "curRow");

        ds_out.setCellData(targetIndex, "sellVatNo", ds_outSellingEvidenceList.getCellData(i, "sellVatNo"));
		ds_out.setCellData(targetIndex, "slipNo", ds_outSellingEvidenceList.getCellData(i, "slipNo"));
		ds_out.setCellData(targetIndex, "dcsnClsNm", ds_outSellingEvidenceList.getCellData(i, "dcsnClsNm"));

		if (i == rowcnt) {
            ds_out.setRowPosition(targetIndex);
			ds_out.setCellData(targetIndex, "choice", "F");

			//ds_out.ColumnProp('choice', 'Edit') = "None";
            gr_detail.setColumnReadOnly('choice', true);

			//gr_detail.ColumnProp('choice', 'Show') = "false";
            gr_detail.setColumnVisible('choice', false);
		}
	}
};

//-------------------------------------------------------------------------
// 그리드 이벤트
//-------------------------------------------------------------------------
scwin.gr_out_onrowindexchange = function (rowIndex, oldRow) {
    scwin.f_onFilter(rowIndex);
};

scwin.gr_out_oncellclick = async function (rowIndex, columnIndex, columnId) {
    if (rowIndex > -1) {
		if (ds_out.getCellData(rowIndex, "slipNo") != null && ds_out.getCellData(rowIndex, "slipNo") != "") {
			await scwin.f_DetailRetrieve(rowIndex);
		}
    }

    if (columnId == "button" && rowIndex >= 0) {
        var	transRow;

        $c.gus.cfCopyDataSetHeader(ds_out, ds_sellingEvidence);

        transRow = ds_out.getRowData(rowIndex);   
        var toIdx = ds_sellingEvidence.insertRow();
        ds_sellingEvidence.setRowData(toIdx, transRow, "true");

        ds_sellingEvidence.setCellData(0, "curRow", rowIndex);

	   	$c.gus.cfCopyDataSet(ds_detail, ds_commonCopyList);
        ds_commonCopyList.removeAll();

        for (var i = 0; i < ds_detail.getAllFilteredJSON().length; i++){
            ds_commonCopyList.setRowJSON(i, ds_detail.getAllFilteredJSON()[i]);    
        }

        var valueObject = {};

        // 상세화면 호출
	   	var opts = {
            id : "smpPop"	
          , popupName : "세금계산서개별생성"
          , modal : true
          , type : "browserPopup"
          , width : 1230
          , height : 780
          , title : "세금계산서개별생성"
        };

        await $c.win.openPopup("/ui/ja/dnja/bilg/dnja_210_01_02p.xml", opts, valueObject); 

		if (acb_qryDtConKnd.getValue() == "CERTI") {
            let e = await $c.sbm.execute(sbm_retrieve);
            if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
                scwin.sbm_retrieve_submitdone(e);
            }
   		} else if (acb_qryDtConKnd.getValue() == "SPPLY" || acb_qryDtConKnd.getValue() == "POST") {
            let e = await $c.sbm.execute(sbm_eachSellingEvidenceList);
            if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
                scwin.sbm_eachSellingEvidenceList_submitdone(e);
            }
   		}	
	} 
};

scwin.gr_out_onheaderclick = function (headerId) {
    var i = 0;

	if (headerId == "column1") {
        var choiceYN = gr_out.getHeaderValue(headerId);

		if (choiceYN == "1") {
			for (var i = 0; i < ds_out.getRowCount(); i++) {
				ds_out.setCellData(i, "choice", "T");
			}
		} else {
			for (var i = 0; i < ds_out.getRowCount(); i++) {
				ds_out.setCellData(i, "choice", "F");
			}
		}
	} else if (headerId == "column17") {
        var printChkYN = gr_out.getHeaderValue(headerId);
        if (printChkYN == "1") {
			for (var i = 0; i < ds_out.getRowCount(); i++) {
                ds_out.setCellData(i, "printChk", "T");
			}
		} else {
			for (var i = 0; i < ds_out.getRowCount(); i++) {
                ds_out.setCellData(i, "printChk", "F");
			}
		}
    }
};

scwin.gr_out_onaftercolumnmove = function (info) {
    if (info.rowIndex > -1) {
        if (ds_out.getCellData(info.rowIndex, "slipNo") != null && ds_out.getCellData(info.rowIndex, "slipNo") != "") {
            scwin.f_DetailRetrieve(info.rowIndex);
        }
    }	
};

scwin.gr_out_CustomFormatter = function(data, formattedData, rowIndex, colIndex) {
    let columnId =  $c.util.getComponent(this.id).getColumnID(colIndex);
    let val = data, color = "black";

    if (columnId == "confirmDt") {
        var confirmDtFr = ds_out.getCellData(rowIndex, 'confirmDtFr');
        var confirmDtTo = ds_out.getCellData(rowIndex, 'confirmDtTo');

        if (!confirmDtFr || !confirmDtTo) {
            return ""; // 데이터가 없으면 빈 문자열 반환 (혹은 "-" 등 원하는 문구)
        }

        if (confirmDtFr.length >= 8 && confirmDtTo.length >= 8) {
            var confirmDtFrStr = confirmDtFr.substring(0, 4) + "/" + confirmDtFr.substring(4, 6) + "/" + confirmDtFr.substring(6, 8);
            var confirmDtToStr = confirmDtTo.substring(0, 4) + "/" + confirmDtTo.substring(4, 6) + "/" + confirmDtTo.substring(6, 8);

            val = confirmDtFrStr + " - " + confirmDtToStr;
        } else {
            val = confirmDtFr + " - " + confirmDtTo; // 길이가 모자라면 원본 합쳐서 출력
        }
    } 

    return val;
};

